// Helper functions
const showStatusHTML = (status) => {
  switch (status) {
    case "Draft":
      this.display(["draft_status"]);
      break;
    case "Created":
      this.display(["created_status"]);
      break;
    case "In Progress":
      this.display(["processing_status"]);
      break;
    case "Completed":
      this.display(["completed_status"]);
      break;
    case "Cancelled":
      this.display(["cancelled_status"]);
      break;
    default:
      break;
  }
};

const disabledField = async (status) => {
  if (status === "Completed") {
    this.disabled(
      [
        "to_status",
        "plant_id",
        "to_id",
        "movement_type",
        "ref_doc_type",
        "gd_no",
        "delivery_no",
        "so_no",
        "assigned_to",
        "created_by",
        "created_at",
        "organization_id",
        "ref_doc",
        "table_picking_items",
        "table_picking_records",
        "remarks",
      ],
      true,
    );

    this.hide([
      "button_save_as_draft",
      "button_inprogress",
      "button_completed",
    ]);

    // Disable table rows
    disableTableRows();
  } else {
    if (status === "Created") {
      this.hide(["button_save_as_draft"]);
    }
    this.disabled(["ref_doc"], false);
  }
};

const disableTableRows = () => {
  setTimeout(() => {
    const data = this.getValues();
    const rows = data.table_picking_items || [];

    rows.forEach((row, index) => {
      const fieldNames = Object.keys(row).filter((key) => key !== "picked_qty");

      const fieldsToDisable = fieldNames.map(
        (field) => `table_picking_items.${index}.${field}`,
      );

      this.disabled(fieldsToDisable, true);
    });
  }, 1000);
};

const setPlant = async (organizationId) => {
  const deptId = this.getVarSystem("deptIds").split(",")[0];
  let plantId = "";
  const plant = this.getValue("plant_id");

  if (!plant) {
    if (deptId === organizationId) {
      const resPlant = await db
        .collection("blade_dept")
        .where({ parent_id: deptId })
        .get();

      if (!resPlant && resPlant.data.length === 0) {
        plantId = deptId;
      } else {
        plantId = "";
      }
    } else {
      plantId = deptId;
    }
  }

  this.setData({
    organization_id: organizationId,
    ...(!plant ? { plant_id: plantId } : {}),
    created_at: new Date().toISOString().split("T")[0],
  });
};

const viewSerialNumber = async () => {
  const table_picking_items = this.getValue("table_picking_items");
  const table_picking_records = this.getValue("table_picking_records");
  if (table_picking_items.length > 0) {
    for (const picking of table_picking_items) {
      if (picking.is_serialized_item === 1) {
        await this.display([
          "table_picking_items.select_serial_number",
          "table_picking_items.serial_numbers",
        ]);
      }
    }
  }
  if (table_picking_records.length > 0) {
    for (const picking of table_picking_records) {
      if (picking.serial_numbers !== "" && picking.serial_numbers !== null) {
        await this.display("table_picking_records.serial_numbers");
      }
    }
  }
};

const setSerialNumber = async () => {
  try {
    const table_picking_items = this.getValue("table_picking_items");

    // Check if table_picking_items exists and is an array
    if (
      !Array.isArray(table_picking_items) ||
      table_picking_items.length === 0
    ) {
      console.log("No picking items found or invalid data structure");
      return;
    }

    for (const [index, picking] of table_picking_items.entries()) {
      try {
        // Check if item is serialized
        if (picking.is_serialized_item === 1) {
          console.log(
            `Processing serialized item at index ${index}:`,
            picking.item_code || picking.id,
          );

          // Check if serial_numbers exists and is not empty
          if (
            !picking.serial_numbers ||
            picking.serial_numbers === null ||
            picking.serial_numbers === undefined ||
            typeof picking.serial_numbers !== "string" ||
            picking.serial_numbers.trim() === ""
          ) {
            console.warn(
              `No valid serial numbers found for item at index ${index}`,
            );
            continue;
          }

          console.log("Picking Serial Numbers", picking.serial_numbers);

          // Split and clean serial numbers
          const serialNumbers = picking.serial_numbers
            .split(",")
            .map((sn) => sn.trim())
            .filter((sn) => sn !== "");

          if (serialNumbers.length === 0) {
            console.warn(
              `No valid serial numbers after processing for item at index ${index}`,
            );
            continue;
          }

          console.log(
            `Setting ${serialNumbers.length} serial numbers for item at index ${index}:`,
            serialNumbers,
          );

          // Set option data for select dropdown
          await this.setOptionData(
            [`table_picking_items.${index}.select_serial_number`],
            serialNumbers,
          );

          // Set the actual data
          await this.setData({
            [`table_picking_items.${index}.select_serial_number`]:
              serialNumbers,
          });

          // Disable picked_qty field for serialized items
          await this.disabled(
            [`table_picking_items.${index}.picked_qty`],
            true,
          );

          console.log(
            `Successfully set serial numbers for item at index ${index}`,
          );
        }
      } catch (itemError) {
        console.error(`Error processing item at index ${index}:`, itemError);
        // Continue with next item instead of breaking the entire function
        continue;
      }
    }
  } catch (error) {
    console.error("Error in setSerialNumber function:", error);
    // Don't throw error to prevent breaking the entire onMounted flow
  }
};

const disabledPickedQtyField = async () => {
  const gdIDs = await this.getValue("gd_no");

  const resGD = await Promise.all(
    gdIDs.map((gdId) => db.collection("goods_delivery").doc(gdId).get()),
  );

  const gdData = resGD.map((gd) => gd.data[0]);
  const cancelledGD = gdData.filter((gd) => gd.picking_status === "Cancelled");
  const tablePickingItems = this.getValue("table_picking_items");
  if (tablePickingItems.length > 0) {
    for (const [index, picking] of tablePickingItems.entries()) {
      const cancelGD = cancelledGD.find((gd) => gd.id === picking.gd_id);
      console.log("cancelGD", cancelGD);
      if (picking.line_status === "Cancelled" || cancelGD) {
        setTimeout(async () => {
          this.disabled(
            [
              `table_picking_items.${index}.picked_qty`,
              `table_picking_items.${index}.remark`,
              `table_picking_items.${index}.select_serial_number`,
            ],
            true,
          );
        }, 100);
      }
    }
  }
};

const HU_SELECT_ALLOWED_POLICIES = ["FULL_HU_PICK", "NO_SPLIT"];

const fetchPickingSetup = async () => {
  try {
    const res = await db
      .collection("picking_setup")
      .where({
        plant_id: this.getValue("plant_id"),
        picking_required: 1,
      })
      .get();
    return res.data && res.data.length > 0 ? res.data[0] : null;
  } catch (error) {
    console.error("fetchPickingSetup error:", error);
    return null;
  }
};

const createHeaderRows = async () => {
  const rows = this.getValue("table_picking_items") || [];
  if (rows.length === 0) return;

  if (rows.some((r) => r.row_type === "header")) return;

  const newRows = [];
  let lastHuId = null;

  for (const row of rows) {
    const huId = row.handling_unit_id;
    if (huId && huId !== lastHuId) {
      newRows.push({
        row_type: "header",
        handling_unit_id: huId,
        hu_select: 0,
      });
      lastHuId = huId;
    } else if (!huId) {
      lastHuId = null;
    }
    newRows.push({ ...row, row_type: "item" });
  }

  if (newRows.length !== rows.length) {
    await this.setData({ table_picking_items: newRows });
  }
};

const applyHUVisibility = async (pickingSetup) => {
  const rows = this.getValue("table_picking_items") || [];
  if (rows.length === 0) return;

  const splitPolicy = pickingSetup ? pickingSetup.split_policy : null;
  const huSelectEnabled = HU_SELECT_ALLOWED_POLICIES.includes(splitPolicy);

  // handling_unit_id: enable column-wide so it can be shown on headers; we
  // then per-row hide it on item rows.
  // hu_select: stays hidden by JSON default; we per-row display it on header
  // rows only (and only when split_policy permits). This avoids leaking it
  // onto item rows.
  await this.display("table_picking_items.handling_unit_id");

  const HU_FIELDS = ["handling_unit_id", "hu_select"];
  const sampleItem = rows.find((r) => r.row_type !== "header");
  const itemFields = sampleItem
    ? Object.keys(sampleItem).filter(
        (k) => !HU_FIELDS.includes(k) && k !== "row_type",
      )
    : [];

  // picked_qty has a validator rule and remark accepts input — disable them
  // on header rows so they don't trigger validation or accept input while hidden
  const HEADER_DISABLE_FIELDS = ["picked_qty", "remark"];

  for (const [i, row] of rows.entries()) {
    if (row.row_type === "header") {
      for (const f of itemFields) {
        await this.hide(`table_picking_items.${i}.${f}`);
      }
      if (huSelectEnabled) {
        await this.display(`table_picking_items.${i}.hu_select`);
      }
      for (const f of HEADER_DISABLE_FIELDS) {
        await this.disabled(`table_picking_items.${i}.${f}`, true);
      }
    } else {
      await this.hide(`table_picking_items.${i}.handling_unit_id`);
      // hu_select stays hidden by JSON default on item rows — no per-row call needed
    }
  }

  // Under whole-HU policies, picked_qty on HU-allocated item rows is driven
  // by the header's hu_select — disable manual entry. Loose item rows (no
  // handling_unit_id) stay editable. Header rows were already disabled above.
  if (huSelectEnabled) {
    for (const [i, row] of rows.entries()) {
      if (row.row_type !== "header" && row.handling_unit_id) {
        await this.disabled(`table_picking_items.${i}.picked_qty`, true);
      }
    }
  }
};

const PickingPlan = async (pickingSetup) => {
  try {
    if (!pickingSetup) return;

    if (pickingSetup.picking_after === "Goods Delivery") {
      await this.display(["button_completed"]);
    } else if (pickingSetup.picking_after === "Sales Order") {
      await this.display(["to_validity_period", "to_no"]);
      await this.hide(["gd_no", "delivery_no"]);
    } else {
      await this.display(["button_completed"]);
    }

    const isLoadingBay = pickingSetup.is_loading_bay;
    await this.setData({
      is_loading_bay: isLoadingBay,
    });
    if (isLoadingBay) {
      await this.display([
        "table_picking_items.storage_location",
        "table_picking_items.target_location",
      ]);
    }
  } catch (error) {
    console.error(error);
    this.$message.error(error.message || "An error occurred");
  }
};

// Main execution function
(async () => {
  try {
    let pageStatus = "";
    const status = await this.getValue("to_status");
    console.log("Debug", status, this.getValues());

    if (this.isAdd) pageStatus = "Add";
    else if (this.isEdit) pageStatus = "Edit";
    else if (this.isView) pageStatus = "View";
    else if (this.isCopy) pageStatus = "Clone";
    else throw new Error("Invalid page state");

    let organizationId = this.getVarGlobal("deptParentId");
    if (organizationId === "0") {
      organizationId = this.getVarSystem("deptIds").split(",")[0];
    }

    console.log("pageStatus", pageStatus);
    await this.setData({ page_status: pageStatus });
    console.log("pageStatusData", this.getValue("page_status"));

    switch (pageStatus) {
      case "Add":
        // Add mode
        this.display(["draft_status"]);
        this.disabled("assigned_to", false);
        this.setData({
          page_status: pageStatus,
          created_by: this.getVarGlobal("nickname"),
          movement_type: "Picking",
        });

        await setPlant(organizationId);

        const convertFromGD = this.getValue("plant_id");

        if (convertFromGD) {
          await viewSerialNumber();
          await setSerialNumber();
        }
        {
          const pickingSetup = await fetchPickingSetup();
          await createHeaderRows();
          await applyHUVisibility(pickingSetup);
          await PickingPlan(pickingSetup);
        }
        break;

      case "Edit":
        // this.setData({
        //   "table_picking_items.picked_qty": 0,
        //   "table_picking_items.remark": "",
        // });
        if (status !== "Draft") {
          this.hide(["gd_no", "button_save_as_draft", "button_created"]);
        }
        await disabledField(status);
        await showStatusHTML(status);
        await disabledPickedQtyField();
        await viewSerialNumber();
        await setSerialNumber();
        console.log(
          "table_picking_item onMounted",
          this.getValue("table_picking_items"),
        );
        {
          const pickingSetup = await fetchPickingSetup();
          await createHeaderRows();
          await applyHUVisibility(pickingSetup);
          await PickingPlan(pickingSetup);
        }
        break;

      case "View":
        this.hide(["gd_no"]);
        this.display(["delivery_no"]);
        await showStatusHTML(status);
        this.hide([
          "button_save_as_draft",
          "button_created",
          "button_inprogress",
          "button_completed",
        ]);
        await viewSerialNumber();
        {
          const pickingSetup = await fetchPickingSetup();
          await createHeaderRows();
          await applyHUVisibility(pickingSetup);
          await PickingPlan(pickingSetup);
        }
        break;
    }
  } catch (error) {
    console.error(error);
    this.$message.error(error.message || "An error occurred");
  }
})();

setTimeout(async () => {
  if (!this.isAdd) return;
  const maxRetries = 10;
  const interval = 500;
  for (let i = 0; i < maxRetries; i++) {
    const op = await this.onDropdownVisible("to_id_type", true);
    if (op != null) break;
    await new Promise((resolve) => setTimeout(resolve, interval));
  }
  function getDefaultItem(arr) {
    return arr?.find((item) => item?.item?.is_default === 1);
  }

  const optionsData = this.getOptionData("to_id_type") || [];
  const data = getDefaultItem(optionsData);
  if (data) {
    this.setData({ to_id_type: data.value });
  }
}, 500);

const closeDialog = (data) => {
  if (this.parentGenerateForm) {
    this.parentGenerateForm.$refs.SuPageDialogRef.hide();
    this.parentGenerateForm.refresh();
    if (data.to_no && data.to_no.length > 0) {
      this.parentGenerateForm.hide("custom_41s73hyl");
    } else {
      this.parentGenerateForm.hide("tabs_picking");
    }
  }
};

(async () => {
  try {
    this.showLoading("Saving Picking as Draft...");

    const data = this.getValues();
    console.log("data", data);

    // Header rows in table_picking_items exist for display only — strip them
    // before sending to the workflow.
    if (Array.isArray(data.table_picking_items)) {
      data.table_picking_items = data.table_picking_items.filter(
        (row) => row.row_type !== "header",
      );
    }

    // Ensure data is an array
    const arrayData = Array.isArray(data) ? data : [data];

    let workflowResult;

    await this.runWorkflow(
      "2021065804251615233",
      { arrayData: arrayData, saveAs: "Draft", pageStatus: data.page_status },
      async (res) => {
        console.log("Picking saved successfully:", res);
        workflowResult = res;
      },
      (err) => {
        console.error("Failed to save Picking:", err);
        this.hideLoading();
        workflowResult = err;
      },
    );

    if (!workflowResult || !workflowResult.data) {
      this.hideLoading();
      this.$message.error("No response from workflow");
      return;
    }

    // Handle workflow errors
    if (
      workflowResult.data.code === "400" ||
      workflowResult.data.code === 400 ||
      workflowResult.data.success === false
    ) {
      this.hideLoading();
      const errorMessage =
        workflowResult.data.msg ||
        workflowResult.data.message ||
        "Failed to save Picking";
      this.$message.error(errorMessage);
      return;
    }

    // Handle success
    if (
      workflowResult.data.code === "200" ||
      workflowResult.data.code === 200 ||
      workflowResult.data.success === true
    ) {
      this.hideLoading();
      const successMessage =
        workflowResult.data.message ||
        workflowResult.data.msg ||
        "Picking saved successfully";
      this.$message.success(successMessage);
      closeDialog(arrayData[0]);
    } else {
      this.hideLoading();
      this.$message.error("Unknown workflow status");
    }
  } catch (error) {
    this.hideLoading();
    console.error("Error:", error);
    const errorMessage = error.message || "Failed to save Picking";
    this.$message.error(errorMessage);
  }
})();

const closeDialog = (data) => {
  if (this.parentGenerateForm) {
    this.parentGenerateForm.$refs.SuPageDialogRef.hide();
    this.parentGenerateForm.refresh();
    if (data.to_no && data.to_no.length > 0) {
      this.parentGenerateForm.hide("custom_41s73hyl");
    } else {
      this.parentGenerateForm.hide("tabs_picking");
    }
  }
};

(async () => {
  try {
    this.showLoading("Saving Picking as Completed...");

    const data = this.getValues();
    console.log("data", data);

    // Header rows in table_picking_items exist for display only — strip them
    // before sending to the workflow.
    if (Array.isArray(data.table_picking_items)) {
      data.table_picking_items = data.table_picking_items.filter(
        (row) => row.row_type !== "header",
      );
    }

    // Ensure data is an array
    const arrayData = Array.isArray(data) ? data : [data];

    let workflowResult;

    await this.runWorkflow(
      "2021065804251615233",
      {
        arrayData: arrayData,
        saveAs: "Completed",
        pageStatus: data.page_status,
        confirmed_by: this.getVarGlobal("nickname"),
      },
      async (res) => {
        console.log("Picking saved successfully:", res);
        workflowResult = res;
      },
      (err) => {
        console.error("Failed to save Picking:", err);
        this.hideLoading();
        workflowResult = err;
      },
    );

    if (!workflowResult || !workflowResult.data) {
      this.hideLoading();
      this.$message.error("No response from workflow");
      return;
    }

    // Handle credit limit warnings (402, 403)
    if (
      workflowResult.data.code === "402" ||
      workflowResult.data.code === 402 ||
      workflowResult.data.code === "403" ||
      workflowResult.data.code === 403
    ) {
      this.hideLoading();
      this.$message.warning(
        "Unable to auto complete GD due to Credit Limit. Please complete manually",
      );
      closeDialog(arrayData[0]);
      return;
    }

    // Handle packing not completed warnings (407)
    if (
      workflowResult.data.code === "407" ||
      workflowResult.data.code === 407
    ) {
      this.hideLoading();
      this.$message.warning(
        "Unable to auto complete GD due to Packing not completed.",
      );
      closeDialog(arrayData[0]);
      return;
    }

    // Handle workflow errors
    if (
      workflowResult.data.code === "400" ||
      workflowResult.data.code === 400 ||
      workflowResult.data.success === false
    ) {
      this.hideLoading();
      const errorMessage =
        workflowResult.data.msg ||
        workflowResult.data.message ||
        "Failed to save Picking";
      this.$message.error(errorMessage);
      return;
    }

    // Handle success
    if (
      workflowResult.data.code === "200" ||
      workflowResult.data.code === 200 ||
      workflowResult.data.success === true
    ) {
      this.hideLoading();
      const successMessage =
        workflowResult.data.message ||
        workflowResult.data.msg ||
        "Picking saved successfully";
      this.$message.success(successMessage);
      closeDialog(arrayData[0]);
    } else {
      this.hideLoading();
      this.$message.error("Unknown workflow status");
    }
  } catch (error) {
    this.hideLoading();
    console.error("Error:", error);
    const errorMessage = error.message || "Failed to save Picking";
    this.$message.error(errorMessage);
  }
})();

const closeDialog = () => {
  if (this.parentGenerateForm) {
    this.parentGenerateForm.$refs.SuPageDialogRef.hide();
    this.parentGenerateForm.refresh();
    this.hideLoading();
  }
};

const getPrefixData = async (
  organizationId,
  documentType = "Transfer Order"
) => {
  console.log("Getting prefix data for organization:", organizationId);
  try {
    const prefixEntry = await db
      .collection("prefix_configuration")
      .where({
        document_types: documentType,
        is_deleted: 0,
        organization_id: organizationId,
        is_active: 1,
      })
      .get();

    console.log("Prefix data result:", prefixEntry);

    if (!prefixEntry.data || prefixEntry.data.length === 0) {
      console.log("No prefix configuration found");
      return null;
    }

    return prefixEntry.data[0];
  } catch (error) {
    console.error("Error getting prefix data:", error);
    throw error;
  }
};

const updatePrefix = async (
  organizationId,
  runningNumber,
  documentType = "Transfer Order"
) => {
  console.log(
    "Updating prefix for organization:",
    organizationId,
    "with running number:",
    runningNumber
  );
  try {
    await db
      .collection("prefix_configuration")
      .where({
        document_types: documentType,
        is_deleted: 0,
        organization_id: organizationId,
      })
      .update({
        running_number: parseInt(runningNumber) + 1,
        has_record: 1,
      });
    console.log("Prefix update successful");
  } catch (error) {
    console.error("Error updating prefix:", error);
    throw error;
  }
};

const generatePrefix = (runNumber, now, prefixData) => {
  console.log("Generating prefix with running number:", runNumber);
  try {
    let generated = prefixData.current_prefix_config;
    generated = generated.replace("prefix", prefixData.prefix_value);
    generated = generated.replace("suffix", prefixData.suffix_value);
    generated = generated.replace(
      "month",
      String(now.getMonth() + 1).padStart(2, "0")
    );
    generated = generated.replace(
      "day",
      String(now.getDate()).padStart(2, "0")
    );
    generated = generated.replace("year", now.getFullYear());
    generated = generated.replace(
      "running_number",
      String(runNumber).padStart(prefixData.padding_zeroes, "0")
    );
    console.log("Generated prefix:", generated);
    return generated;
  } catch (error) {
    console.error("Error generating prefix:", error);
    throw error;
  }
};

const checkUniqueness = async (
  generatedPrefix,
  organizationId,
  collection = "transfer_order",
  prefix = "to_id"
) => {
  const existingDoc = await db
    .collection(collection)
    .where({
      [prefix]: generatedPrefix,
      organization_id: organizationId,
      is_deleted: 0,
    })
    .get();

  return !existingDoc.data || existingDoc.data.length === 0;
};

const findUniquePrefix = async (
  prefixData,
  organizationId,
  collection = "transfer_order",
  prefix = "to_id"
) => {
  const now = new Date();
  let prefixToShow;
  let runningNumber = prefixData.running_number || 1;
  let isUnique = false;
  let maxAttempts = 10;
  let attempts = 0;

  while (!isUnique && attempts < maxAttempts) {
    attempts++;
    prefixToShow = generatePrefix(runningNumber, now, prefixData);
    isUnique = await checkUniqueness(
      prefixToShow,
      organizationId,
      collection,
      prefix
    );
    if (!isUnique) {
      runningNumber++;
    }
  }

  if (!isUnique) {
    throw new Error(
      "Could not generate a unique Transfer Order number after maximum attempts"
    );
  }

  return { prefixToShow, runningNumber };
};

const validateForm = (data, requiredFields) => {
  const missingFields = [];

  requiredFields.forEach((field) => {
    const value = data[field.name];

    // Handle non-array fields (unchanged)
    if (!field.isArray) {
      if (validateField(value, field)) {
        missingFields.push(field.label);
      }
      return;
    }

    // Handle array fields
    if (!Array.isArray(value)) {
      missingFields.push(`${field.label}`);
      return;
    }

    if (value.length === 0) {
      missingFields.push(`${field.label}`);
      return;
    }

    // Check each item in the array
    if (field.arrayType === "object" && field.arrayFields && value.length > 0) {
      value.forEach((item, index) => {
        field.arrayFields.forEach((subField) => {
          const subValue = item[subField.name];
          if (validateField(subValue, subField)) {
            missingFields.push(
              `${subField.label} (in ${field.label} #${index + 1})`
            );
          }
        });
      });
    }
  });

  return missingFields;
};

const validateField = (value) => {
  if (value === undefined || value === null) return true;
  if (typeof value === "string") return value.trim() === "";
  if (typeof value === "number") return value <= 0;
  if (Array.isArray(value)) return value.length === 0;
  if (typeof value === "object") return Object.keys(value).length === 0;
  return !value;
};

// Helper function to calculate leftover serial numbers after partial processing
const calculateLeftoverSerialNumbers = (item) => {
  // Only process serialized items
  if (item.is_serialized_item !== 1) {
    return item.serial_numbers; // Return original if not serialized
  }

  // Get the original serial numbers and processed serial numbers
  const originalSerialNumbers = item.serial_numbers
    ? item.serial_numbers
        .split(",")
        .map((sn) => sn.trim())
        .filter((sn) => sn !== "")
    : [];

  const processedSerialNumbers = Array.isArray(item.select_serial_number)
    ? item.select_serial_number.map((sn) => sn.trim()).filter((sn) => sn !== "")
    : [];

  console.log(
    `Item ${
      item.item_code || item.item_id
    }: Original serial numbers: [${originalSerialNumbers.join(", ")}]`
  );
  console.log(
    `Item ${
      item.item_code || item.item_id
    }: Processed serial numbers: [${processedSerialNumbers.join(", ")}]`
  );

  // Calculate leftover serial numbers by removing processed ones
  const leftoverSerialNumbers = originalSerialNumbers.filter(
    (originalSN) => !processedSerialNumbers.includes(originalSN)
  );

  console.log(
    `Item ${
      item.item_code || item.item_id
    }: Leftover serial numbers: [${leftoverSerialNumbers.join(", ")}]`
  );

  // Return the leftover serial numbers as a comma-separated string
  return leftoverSerialNumbers.length > 0
    ? leftoverSerialNumbers.join(", ")
    : "";
};

// Enhanced quantity validation and line status determination
const validateAndUpdateLineStatuses = (pickingItems) => {
  const errors = [];
  const updatedItems = JSON.parse(JSON.stringify(pickingItems));

  for (let index = 0; index < updatedItems.length; index++) {
    const item = updatedItems[index];

    // Safely parse quantities
    const qtyToPick = parseFloat(item.qty_to_pick) || 0;
    const pendingProcessQty = parseFloat(item.pending_process_qty) || 0;
    const pickedQty = parseFloat(item.picked_qty) || 0;

    console.log(
      `Item ${
        item.item_id || index
      }: qtyToPick=${qtyToPick}, pendingProcessQty=${pendingProcessQty}, pickedQty=${pickedQty}`
    );

    // Validation checks
    if (pickedQty < 0) {
      errors.push(
        `Picked quantity cannot be negative for item ${
          item.item_id || `#${index + 1}`
        }`
      );
      continue;
    }

    if (pickedQty > pendingProcessQty) {
      errors.push(
        `Picked quantity (${pickedQty}) cannot be greater than quantity to pick (${pendingProcessQty}) for item ${
          item.item_id || `#${index + 1}`
        }`
      );
      continue;
    }

    // Determine line status based on quantities
    let lineStatus;
    if (pickedQty === 0) {
      lineStatus = null;
    } else if (pickedQty === pendingProcessQty) {
      lineStatus = "Completed";
    } else if (pickedQty < pendingProcessQty) {
      lineStatus = "In Progress";
    }

    // Calculate pending process quantity
    const pending_process_qty = pendingProcessQty - pickedQty;

    // Update line status and pending process quantity
    updatedItems[index].line_status = lineStatus;
    updatedItems[index].pending_process_qty = pending_process_qty;

    // Update serial numbers for serialized items - calculate leftover serial numbers
    if (item.is_serialized_item === 1 && pending_process_qty > 0) {
      const leftoverSerialNumbers = calculateLeftoverSerialNumbers(item);
      updatedItems[index].serial_numbers = leftoverSerialNumbers;
      console.log(
        `Updated serial_numbers for partially processed item ${
          item.item_code || item.item_id
        }: "${leftoverSerialNumbers}"`
      );
    } else if (item.is_serialized_item === 1 && pending_process_qty === 0) {
      // If fully processed, clear serial numbers
      updatedItems[index].serial_numbers = "";
      console.log(
        `Cleared serial_numbers for fully processed item ${
          item.item_code || item.item_id
        }`
      );
    }

    console.log(`Item ${item.item_id || index} line status: ${lineStatus}`);
  }

  return { updatedItems, errors };
};

const addEntry = async (organizationId, toData) => {
  try {
    const prefixData = await getPrefixData(organizationId, "Transfer Order");

    if (prefixData) {
      const { prefixToShow, runningNumber } = await findUniquePrefix(
        prefixData,
        organizationId,
        "transfer_order",
        "to_id"
      );

      await updatePrefix(organizationId, runningNumber, "Transfer Order");
      toData.to_id = prefixToShow;
    } else {
      const isUnique = await checkUniqueness(
        toData.to_id,
        organizationId,
        "transfer_order",
        "to_id"
      );
      if (!isUnique) {
        throw new Error(
          `Picking Number "${toData.to_id}" already exists. Please use a different number.`
        );
      }
    }

    for (const item of toData.table_picking_items) {
      if (item.select_serial_number) {
        item.select_serial_number = null;
      }
    }

    // Add the record
    const createdRecord = await db.collection("transfer_order").add(toData);

    if (!createdRecord.data || createdRecord.data.length === 0) {
      throw new Error("Failed to retrieve created transfer order record");
    }

    const toId = createdRecord.data[0].id;
    console.log("Transfer order created successfully with ID:", toId);

    return toId; // Return the created ID
  } catch (error) {
    console.error("Error in addEntry:", error);
    throw error;
  }
};

const updateEntry = async (organizationId, toData, toId, originalToStatus) => {
